            var endpoint = AddServiceEndpoint(typeof(IHealthcareRecordsService), binding, "");

            Description.Behaviors.Add(new ServiceMetadataBehavior { HttpsGetEnabled = true, HttpsGetUrl = new Uri(baseAddress, "mex") });
