            Credentials.ServiceCertificate.Certificate = serviceCert;

            if (!string.IsNullOrWhiteSpace(settings.ClientCertificateThumbprint))
            {
                var clientCert = WsSecurityConfiguration.FindCert(settings.ClientCertificateStoreName, settings.ClientCertificateStoreLocation, settings.ClientCertificateThumbprint);
                Credentials.ClientCertificate.Certificate = clientCert;
            }

            Credentials.ClientCertificate.Authentication.CertificateValidationMode = System.ServiceModel.Security.X509CertificateValidationMode.ChainTrust;
            Credentials.ClientCertificate.Authentication.RevocationMode = X509RevocationMode.Online;

            Authorization.PrincipalPermissionMode = PrincipalPermissionMode.UseWindowsGroups;

            Description.Behaviors.Add(new SecurityHeaderBehavior(TimeSpan.FromMinutes(settings.MaxClockSkewMinutes)));
        }
    }

