        private static T ParseEnum<T>(string value, T fallback) where T : struct
        {
            if (string.IsNullOrWhiteSpace(value)) return fallback;
            if (Enum.TryParse<T>(value, ignoreCase: true, out var parsed)) return parsed;
            return fallback;
        }
